// Proven high-yield combos (tested: 20-60% leads without website)
const CITIES = [
  'Laredo TX','Lubbock TX','Corpus Christi TX','Little Rock AR','Wichita KS',
  'Milwaukee WI','Fresno CA','Modesto CA','Bakersfield CA','Stockton CA',
  'Baton Rouge LA','Shreveport LA','Jackson MS','Huntsville AL','Mobile AL',
  'Amarillo TX','Beaumont TX','Midland TX','Brownsville TX','Killeen TX',
  'Savannah GA','Macon GA','Augusta GA','Columbus GA','Albany GA',
  'Fayetteville NC','Greenville SC','Columbia SC','Spartanburg SC','Knoxville TN',
  'Chattanooga TN','Clarksville TN','Murfreesboro TN','Peoria IL','Rockford IL',
  'Spokane WA','Tacoma WA','Yakima WA','Salinas CA','Visalia CA',
  'Gainesville FL','Ocala FL','Cape Coral FL','Lakeland FL','Palm Bay FL'
];
const INDUSTRIES = [
  'landscaper','handyman','tree service','fence contractor','tile installer',
  'pest control','house cleaning','pool service','concrete contractor','irrigation repair',
  'roofer','painter','garage door repair','carpet cleaning','pressure washing',
  'plumber','electrician','hvac contractor','window cleaning','gutter cleaning'
];
const LEADS_PER_RUN = 5;

// Search 10 random combos per run, take first 5 leads total
const seen = new Set();
const combos = [];
while (combos.length < 10) {
  const city = CITIES[Math.floor(Math.random() * CITIES.length)];
  const industry = INDUSTRIES[Math.floor(Math.random() * INDUSTRIES.length)];
  const key = city + '|' + industry;
  if (!seen.has(key)) {
    seen.add(key);
    combos.push({ city, industry, leads_per_run: LEADS_PER_RUN, search_query: industry + ' in ' + city });
  }
}
return combos.map(c => ({ json: c }));

const configItems = $('Set Config & Target').all();
const results = [];
const allInput = $input.all();

for (let i = 0; i < allInput.length; i++) {
  const placesResp = allInput[i].json;
  const cfg = (configItems[i] || configItems[0]).json;
  const city = cfg.city || '';
  const industry = cfg.industry || '';
  const limit = cfg.leads_per_run || 5;
  const places = placesResp.places || [];

  const leads = places
    .filter(p => !p.websiteUri && p.nationalPhoneNumber && p.businessStatus !== 'CLOSED_PERMANENTLY')
    .slice(0, limit)
    .map(p => ({
      business_name: (p.displayName && p.displayName.text) || '',
      phone: p.nationalPhoneNumber.replace(/[^0-9+]/g, ''),
      address: p.formattedAddress || '',
      industry,
      city: city.split(' ')[0],
      state: city.split(' ')[1] || '',
      rating: p.rating || 0,
      reviews_count: p.userRatingCount || 0,
      place_id: p.id,
      status: 'new'
    }));
  results.push(...leads.map(l => ({ json: l })));
}
return results.length ? results : [];

const staticData = $getWorkflowStaticData('global');
const called = staticData.calledNumbers || {};
const calledPlaces = staticData.calledPlaces || {};
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const phone = (j.phone || '').replace(/\D/g, '');
  const placeId = j.place_id || '';
  if (!phone || phone.length < 7) continue;
  if (called[phone]) continue;
  if (placeId && calledPlaces[placeId]) continue;
  out.push({ json: j });
}
return out;

const staticData = $getWorkflowStaticData('global');
if (!staticData.leads) staticData.leads = [];
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  if (staticData.leads.length >= 500) staticData.leads = staticData.leads.slice(-400);
  staticData.leads.push({
    business_name: j.business_name || '',
    phone: j.phone || '',
    industry: j.industry || '',
    city: j.city || '',
    rating: j.rating || '',
    reviews_count: j.reviews_count || 0,
    place_id: j.place_id || '',
    preview_url: j.preview_url || '',
    status: 'new',
    added_at: new Date().toISOString()
  });
  out.push({ json: j });
}
return out;

const staticData = $getWorkflowStaticData('global');
if (!staticData.calledNumbers) staticData.calledNumbers = {};
if (!staticData.calledPlaces) staticData.calledPlaces = {};
if (!staticData.leads) staticData.leads = [];
const payloads = $('Build VAPI Payload').all();
const out = [];
const all = $input.all();
for (let i = 0; i < all.length; i++) {
  const resp = all[i].json;
  const lead = (payloads[i] || {}).json || {};
  const callOk = !!resp.id && !resp.error;
  const phone = (lead.phone || '').replace(/\D/g, '');
  const placeId = lead.place_id || '';
  const now = new Date().toISOString();
  if (callOk && phone) staticData.calledNumbers[phone] = now;
  if (callOk && placeId) staticData.calledPlaces[placeId] = now;
  if (callOk) {
    const idx = staticData.leads.findIndex(l => (l.phone||'').replace(/\D/g,'') === phone);
    if (idx >= 0) { staticData.leads[idx].status = 'called'; staticData.leads[idx].called_at = now; }
  }
  out.push({ json: { call_ok: callOk, call_id: resp.id || '', business_name: lead.business_name || '', phone } });
}
return out;

const staticData = $getWorkflowStaticData('global');
const previewEnabled = staticData.preview_enabled !== false;

const configItems = $('Skip If Already Called').all();
const detailItems = $input.all();
const out = [];

for (let i = 0; i < detailItems.length; i++) {
  const details = detailItems[i].json || {};
  const lead = (configItems[i] || configItems[0]).json;

  const rawPhone = details.nationalPhoneNumber || lead.phone || '';
  const phone = rawPhone.replace(/\D/g, '').replace(/^1/, '');
  if (!phone || phone.length < 10) continue;

  const rating = details.rating || lead.rating || 0;
  const reviews_count = details.userRatingCount || lead.reviews_count || 0;

  const reviews = details.reviews || [];
  const top_review = reviews.length > 0 && reviews[0].text && reviews[0].text.text
    ? reviews[0].text.text.substring(0, 120).replace(/\n/g, ' ')
    : '';

  // Echten Rezensenten-Namen finden (Vorname reicht, klingt natuerlicher)
  let reviewer_name = '';
  for (const rv of reviews) {
    const full = rv.authorAttribution && rv.authorAttribution.displayName ? rv.authorAttribution.displayName : '';
    const first = full.split(' ')[0] || '';
    // Nur echte Namen, keine Firmen/Kuerzel
    if (first.length >= 3 && /^[A-Z][a-z]+$/.test(first)) { reviewer_name = first; break; }
  }

  const is_open = details.currentOpeningHours ? details.currentOpeningHours.openNow : undefined;
  const hours_note = is_open === true ? 'currently open' : is_open === false ? 'currently closed' : '';

  const qs = 'name=' + encodeURIComponent(lead.business_name) +
             '&type=' + encodeURIComponent(lead.industry) +
             '&city=' + encodeURIComponent(lead.city) +
             '&phone=' + encodeURIComponent(phone);
  const preview_url = 'https://teamgoldllc.de/preview?' + qs;

  const wa_message = `Hey ${lead.business_name}! Ryan from Team Gold here - we actually built you a FREE website preview. Take a look:
${preview_url}

Like it? Book a free 15-min call with our developer Atakan and it's yours:
https://cal.com/atakanoztunc/30min

Who we are: https://teamgoldllc.de
Questions? WhatsApp us: https://wa.me/201069564012`;

  out.push({ json: { ...lead, phone, rating, reviews_count, top_review,
    reviewer_name, hours_note, preview_url, wa_message } });
}
return out.length ? out : [];

const staticData = $getWorkflowStaticData('global');
if (!staticData.leads) staticData.leads = [];
if (!staticData.calledNumbers) staticData.calledNumbers = {};

const b = $json.body || {};
const phone = (b.phone || '').replace(/\D/g, '').replace(/^1/, '');
if (!phone) return [{ json: { ok: false, reason: 'no phone' } }];

const now = new Date().toISOString();
const idx = staticData.leads.findIndex(l => (l.phone||'').replace(/\D/g,'').replace(/^1/,'') === phone);
if (idx >= 0) {
  staticData.leads[idx].outcome = b.outcome || '';
  staticData.leads[idx].duration_seconds = b.duration_seconds || 0;
  staticData.leads[idx].summary = (b.summary || '').substring(0, 300);
  staticData.leads[idx].result_at = now;
  if (b.outcome === 'meeting_booked') staticData.leads[idx].status = 'meeting_booked';
  else if (b.outcome === 'callback_requested') staticData.leads[idx].status = 'callback';
}

// Blacklist: never call again if customer asked to be removed
if (b.removed_from_list === true || b.outcome === 'removed_from_list') {
  staticData.calledNumbers[phone] = 'BLACKLISTED';
  if (idx >= 0) staticData.leads[idx].status = 'blacklisted';
}

return [{ json: { ok: true, phone, updated: idx >= 0 } }];

const staticData = $getWorkflowStaticData('global');
const leads = staticData.leads || [];
const called = staticData.calledNumbers || {};
const stats = {
  total_leads: leads.length,
  called: leads.filter(l => l.status === 'called').length,
  meetings_booked: leads.filter(l => l.status === 'meeting_booked').length,
  callbacks: leads.filter(l => l.status === 'callback').length,
  blacklisted: Object.values(called).filter(v => v === 'BLACKLISTED').length,
  total_numbers_tracked: Object.keys(called).length
};
return [{ json: { stats, leads: leads.slice(-100).reverse() } }];

const staticData = $getWorkflowStaticData('global');
const leads = staticData.leads || [];
const called = staticData.calledNumbers || {};
const threeDaysAgo = Date.now() - 3*24*60*60*1000;

const due = leads.filter(l =>
  l.status === 'called' &&
  ['no_answer','voicemail',''].includes(l.outcome || '') &&
  !l.follow_up_sent &&
  l.called_at && new Date(l.called_at).getTime() < threeDaysAgo &&
  called[(l.phone||'').replace(/\D/g,'').replace(/^1/,'')] !== 'BLACKLISTED'
).slice(0, 5);

return due.map(l => {
  const payload = {
    phoneNumberId: 'f6e18747-7105-471c-b611-68048eeb2a1f',
    assistantId: 'bdcc6edf-095f-4cdc-93d5-a138be0b1c0b',
    customer: {
      number: '+1' + String(l.phone || '').replace(/[^0-9]/g, '').slice(-10),
      name: l.business_name || ''
    },
    assistantOverrides: {
      variableValues: {
        business_name: l.business_name || '',
        industry: l.industry || '',
        city: l.city || '',
        rating: String(l.rating || ''),
        reviews_count: String(l.reviews_count || '0'),
        top_review: l.top_review || '',
        reviewer_name: l.reviewer_name || '',
        preview_url: l.preview_url || '',
        is_followup: 'true'
      }
    }
  };
  return { json: { ...l, vapi_body: JSON.stringify(payload) } };
});

const staticData = $getWorkflowStaticData('global');
const leads = staticData.leads || [];
const due = $('Find No-Answer Leads (3+ Days)').all().map(i => i.json);
const out = [];
for (const lead of due) {
  const phone = (lead.phone || '').replace(/\D/g,'').replace(/^1/,'');
  const idx = leads.findIndex(l => (l.phone||'').replace(/\D/g,'').replace(/^1/,'') === phone);
  if (idx >= 0) {
    leads[idx].follow_up_sent = true;
    leads[idx].follow_up_at = new Date().toISOString();
  }
  out.push({ json: { ok: true, phone } });
}
return out.length ? out : [{ json: { ok: true, count: 0 } }];

const items = $input.all();
const text = 'PIPELINE GESTARTET (' + new Date().toLocaleString('de-DE') + ')

Suche heute ' + items.length + ' Kombinationen:
' + items.map(i => '- ' + i.json.search_query).join('
