const staticData = $getWorkflowStaticData('global');
if (staticData.calls_enabled === false) return [];

const out = [];
const MAX_CALLS = 5;
const skipped = [];
for (const item of $input.all()) {
  const l = item.json;
  if (l.error) { skipped.push('err'); continue; }
  let digits = String(l.phone || '').replace(/[^0-9]/g, '');
  if (digits.length === 11 && digits.startsWith('1')) digits = digits.slice(1);
  if (digits.length !== 10) { skipped.push(l.business_name || '?'); continue; }
  if (out.length >= MAX_CALLS) break;
  const payload = {
    phoneNumberId: 'f6e18747-7105-471c-b611-68048eeb2a1f',
    assistantId: 'bdcc6edf-095f-4cdc-93d5-a138be0b1c0b',
    customer: { number: '+1' + digits, name: l.business_name || '' },
    assistantOverrides: {
      variableValues: {
        business_name: l.business_name || '',
        industry: l.industry || '',
        city: l.city || '',
        rating: String(l.rating || ''),
        reviews_count: String(l.reviews_count || '0'),
        top_review: l.top_review || '',
        reviewer_name: l.reviewer_name || '',
        preview_url: l.preview_url || ''
      }
    }
  };
  out.push({ json: { ...l, phone: digits, vapi_body: JSON.stringify(payload) } });
}
return out;

const body = $input.first().json.body || $input.first().json;
const module = body.module;
const enabled = body.enabled;
const staticData = $getWorkflowStaticData('global');

if (module === 'paused') staticData.paused = !!enabled;
else if (module === 'calls') staticData.calls_enabled = enabled;
else if (module === 'sms') staticData.sms_enabled = enabled;
else if (module === 'preview') staticData.preview_enabled = enabled;

return [{ json: { success: true, module, enabled,
  paused: staticData.paused === true,
  calls_enabled: staticData.calls_enabled !== false,
  sms_enabled: staticData.sms_enabled !== false,
  preview_enabled: staticData.preview_enabled !== false
} }];

const staticData = $getWorkflowStaticData('global');
const today = new Date().toISOString().slice(0,10);
const dayData = (staticData.dailyCosts || {})[today] || {calls:0, count:0};
const todayResults = (staticData.callResults || []).filter(r => (r.timestamp||'').startsWith(today));

const pipeOk = staticData.paused !== true;
const callsOk = staticData.calls_enabled !== false;
const smsOk = staticData.sms_enabled !== false;
const previewOk = staticData.preview_enabled !== false;

let text = 'SYSTEM STATUS:\n\n';
text += 'Pipeline: ' + (pipeOk ? 'AN' : 'GESTOPPT') + '\n';
text += 'Anrufe: ' + (callsOk ? 'AN' : 'AUS') + '\n';
text += 'SMS: ' + (smsOk ? 'AN' : 'AUS') + '\n';
text += 'Website-Preview: ' + (previewOk ? 'AN' : 'AUS') + '\n';
text += '\nTagesausgaben: $' + (dayData.calls||0).toFixed(2) + '\n';
text += 'Anrufe heute: ' + todayResults.length + '\n';
text += 'Leads gespeichert: ' + (staticData.leads||[]).length + '\n';

return [{ json: { status_text: text } }];

