    text += '   Tel: ' + (l.phone || '-') + '\n';
    text += '   Maps: ' + mapsUrl + '\n';
    if (previewUrl) text += '   Preview: ' + previewUrl + '\n';
    text += '   Status: ' + (l.outcome || l.status || 'neu') + '\n';
    text += '\n';
  });
}

return [{ json: { leads_text: text } }];

