text += '- "Entferne Miami"\n';
text += '- "Nur Restaurants anrufen"';

return [{ json: { einstellungen_text: text, cities, industries, max_calls: maxCalls } }];

const body = $input.first().json.body || $input.first().json;
const action = body.action;
const value = body.value;
const staticData = $getWorkflowStaticData('global');
if (!staticData.config) staticData.config = {};

let reply = 'Erledigt.';

if (action === 'set_cities') {
  staticData.config.cities = Array.isArray(value) ? value : [value];
  reply = 'Staedte gesetzt: ' + staticData.config.cities.join(', ');
} else if (action === 'add_city') {
  if (!staticData.config.cities) staticData.config.cities = [];
  if (!staticData.config.cities.includes(value)) staticData.config.cities.push(value);
  reply = 'Stadt hinzugefuegt: ' + value;
} else if (action === 'remove_city') {
  if (staticData.config.cities) {
    staticData.config.cities = staticData.config.cities.filter(c => c.toLowerCase() !== String(value).toLowerCase());
  }
  reply = 'Stadt entfernt: ' + value;
} else if (action === 'set_industries') {
  staticData.config.industries = Array.isArray(value) ? value : [value];
  reply = 'Branchen gesetzt: ' + staticData.config.industries.join(', ');
} else if (action === 'set_max_calls') {
  staticData.config.max_calls = parseInt(value) || 10;
  reply = 'Max Anrufe pro Tag: ' + staticData.config.max_calls;
} else if (action === 'reset_config') {
  staticData.config = {};
  reply = 'Einstellungen zurueckgesetzt auf Standard.';
}

return [{ json: { success: true, action, reply } }];
